package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreEmptyLines(), "Default format should not ignore empty lines");

        CSVFormat newFormat = format.withIgnoreEmptyLines();
        assertNotNull(newFormat, "Returned format should not be null");
        assertTrue(newFormat.getIgnoreEmptyLines(), "Format should ignore empty lines after withIgnoreEmptyLines()");

        // The original format should remain unchanged (immutability)
        assertFalse(format.getIgnoreEmptyLines(), "Original format should remain unchanged");

        // Also test withIgnoreEmptyLines(true) returns equivalent result
        CSVFormat newFormatExplicit = format.withIgnoreEmptyLines(true);
        assertEquals(newFormat, newFormatExplicit, "withIgnoreEmptyLines() and withIgnoreEmptyLines(true) should be equal");
    }
}
